Some code:
```python
# events_base.SubscriptionBase
def subscribe(self, ...):
    ...

    def success(headers):
        ...

    with self.subscriptions.subscriptions_lock:
        return self._request('SUBSCRIBE', service.base_url + service.event_subscription_url,
            headers, success)
```

```python
# events.Subscription
def _request(self, method, url, headers, success=None, failure=None):
    try:
        response = requests.request(method, url, headers=headers)
        response.raise_for_status()
    except requests.exceptions.RequestException as exc:
        if failure:
            failure(exc)
    else:
        if success:
            success(response.headers)
        return self
```

```python
# events_twisted.Subscription
def _request(self, method, url, headers, success=None, failure=None):
    ...
    d = agent.request(*args)

    if success:
        def on_success(response):
            ...
            success(response_headers)
            return self
        d.addCallback(on_success)
    
    if failure:
        def on_failure(fail):
            failure(fail.value)
        d.addErrback(on_failure)

    d.subscription = self
    return d
```

